// ============================================
// SMART BIDDER v2.0 - BULLET-PROOF EDITION
// ============================================
// Features:
// 1. Distributed lock check
// 2. State machine awareness
// 3. Escalation levels (0-4)
// 4. Rate limiting (max 3 changes/day, cooldown 2h)
// 5. Time-of-day patterns (evening=cheap, morning=expensive)
// 6. Warmup with MAX bid (not min)
// 7. Rollback snapshots
// 8. Conservative mode support
// 9. Per-teaser spend limits (maxCPL * 10-12)
// 10. API response verification

const lockData = $('Check Locks & Emergency').first().json;
const statsItems = $('Fetch Ad Stats').first().json;
const adsItems = $('Fetch Active Ads').first().json;
const crmItems = $('Fetch CRM Leads').all().map(i => i.json);
const posItems = $('Fetch Positions').all().map(i => i.json);
const geoPayoutItems = $('Fetch Geo Payouts').all().map(i => i.json);
const bidHistoryItems = $('Fetch Recent Bid History').all().map(i => i.json);
const teaserStateItems = $('Fetch Teaser States').all().map(i => i.json);

// --- CONSERVATIVE MODE CHECK ---
const isConservative = !!lockData?.conservative_mode;

// --- PARSE DATA ---
const statsData = statsItems?.data?.result?.data || statsItems?.data || (Array.isArray(statsItems) ? statsItems : []);
const adsData = adsItems?.data?.result?.data || adsItems?.data || (Array.isArray(adsItems) ? adsItems : []);

// Validate data
if (!Array.isArray(statsData) || !Array.isArray(adsData)) {
  return [{ json: { error: 'Invalid data from API', action: 'ABORT' } }];
}

// Empty stats = possible API issue, don't make decisions
if (statsData.length === 0 && adsData.length > 0) {
  return [{ json: { error: 'Empty stats but active ads exist - possible API issue', action: 'ABORT' } }];
}

// --- MAPS ---

// Geo payouts
const geoMap = {};
const DEFAULT_PAYOUT = { avg_payout: 1350, avg_approval: 0.055, max_cpl: 74.25, min_bid: 0.01, max_bid: 0.15 };
geoPayoutItems.forEach(row => {
  if (row.country_code) {
    geoMap[row.country_code] = {
      avg_payout: Number(row.avg_payout) || DEFAULT_PAYOUT.avg_payout,
      avg_approval: Number(row.avg_approval) || DEFAULT_PAYOUT.avg_approval,
      max_cpl: Number(row.max_cpl) || DEFAULT_PAYOUT.max_cpl,
      min_bid: Number(row.min_bid) || DEFAULT_PAYOUT.min_bid,
      max_bid: Number(row.max_bid) || DEFAULT_PAYOUT.max_bid
    };
  }
});

// CRM
const crmMap = {};
crmItems.forEach(row => {
  const adId = Number(row.ad_id);
  if (adId) crmMap[adId] = { leads: row.total_leads || 0, deps: row.depositors || 0, rev: Number(row.crm_revenue) || 0 };
});

// Positions
const posMap = {};
posItems.forEach(row => {
  const adId = Number(row.ad_id);
  if (adId) posMap[adId] = { avg: Number(row.avg_position) || 99, best: Number(row.best_position) || 99 };
});

// Bid history: ad_id -> [changes sorted newest first]
const bidHistoryMap = {};
bidHistoryItems.forEach(row => {
  const adId = Number(row.ad_id);
  if (!bidHistoryMap[adId]) bidHistoryMap[adId] = [];
  bidHistoryMap[adId].push(row);
});

// Teaser states: ad_id -> state info
const stateMap = {};
teaserStateItems.forEach(row => {
  const adId = Number(row.ad_id);
  if (adId) stateMap[adId] = row;
});

// Ads map
const adsMap = {};
adsData.forEach(ad => {
  let currentBid = 0;
  const geos = [];
  if (ad.bids && Array.isArray(ad.bids)) {
    const extractBidsAndGeos = (node) => {
      if (node.bid) currentBid = currentBid || Number(node.bid);
      if (node.type === 'countries' && node.id) {
        geos.push(node.id);
        if (node.bid) currentBid = currentBid || Number(node.bid);
      }
      if (node.children) {
        const children = Array.isArray(node.children) ? node.children : Object.values(node.children);
        children.forEach(c => extractBidsAndGeos(c));
      }
    };
    ad.bids.forEach(b => extractBidsAndGeos(b));
  }
  adsMap[ad.id] = { current_bid: currentBid, ad_group_id: ad.ad_group_id, status_id: ad.status_id, geos };
});

// --- TIME-OF-DAY MULTIPLIER ---
// After 19:00 auction is 3-4x cheaper -> can be more aggressive with bids
// After 08:00 auction gets expensive -> be more conservative
const now = new Date();
const hour = now.getHours();

let timeMultiplier = 1.0;
let timePeriod = 'day';
if (hour >= 19 || hour < 2) {
  // Evening/night: auction is cheap, can raise bids more aggressively
  timeMultiplier = 1.5;  // 50% more aggressive on raises
  timePeriod = 'evening_cheap';
} else if (hour >= 2 && hour < 8) {
  // Deep night: very low traffic
  timeMultiplier = 0.7;
  timePeriod = 'night_low';
} else if (hour >= 8 && hour < 12) {
  // Morning: auction gets expensive
  timeMultiplier = 0.8;
  timePeriod = 'morning_expensive';
} else {
  // Afternoon: normal
  timeMultiplier = 1.0;
  timePeriod = 'afternoon_normal';
}

// --- RATE LIMITING CONFIG ---
const MAX_BID_CHANGES_PER_DAY = 3;
const MIN_COOLDOWN_HOURS = 2;  // Minimum time between changes for same ad
const MAX_CUMULATIVE_CHANGE_DOWN = 0.5;  // Max 50% cumulative decrease per day
const MAX_CUMULATIVE_CHANGE_UP = 2.0;    // Max 2x cumulative increase per day

// --- SPEND THRESHOLDS (4x from original as per user feedback) ---
const minSpendForDecision = 200;   // was $50 -> now $200
const minSpendForStop = 600;       // was $150 -> now $600
const minClicksForStop = 500;

// --- ESCALATION LEVELS ---
// Level 0: Observation (spend < threshold)
// Level 1: Soft correction (-8%, cooldown 2h)
// Level 2: Moderate correction (-15%, cooldown 4h)
// Level 3: Aggressive correction (-25%, to min_bid)
// Level 4: STOP teaser

const getEscalationAction = (level, cpl, maxCPL, spend, leads, failedAttempts, isConservativeMode) => {
  // In conservative mode, only allow HOLD and LOWER actions
  if (spend < minSpendForDecision && leads === 0) {
    return { level: 0, action: 'HOLD', multiplier: 1.0, cooldown: 0, reason: 'observation' };
  }

  if (leads > 0 && cpl <= maxCPL) {
    if (isConservativeMode) {
      return { level: 0, action: 'HOLD', multiplier: 1.0, cooldown: 0, reason: 'conservative_mode_hold' };
    }
    return null; // Will be handled by the profitable logic below
  }

  // No leads or CPL > maxCPL -> escalation
  if (leads === 0 && spend >= minSpendForStop && failedAttempts >= 3) {
    return { level: 4, action: 'STOP', multiplier: 0, cooldown: 0, reason: 'escalation_L4_stop' };
  }
  if (leads > 0 && cpl > maxCPL * 2.0 || failedAttempts >= 3) {
    return { level: 3, action: 'LOWER_BID', multiplier: 0.75, cooldown: 6, reason: 'escalation_L3_aggressive' };
  }
  if (leads > 0 && cpl > maxCPL * 1.3 || failedAttempts >= 2) {
    return { level: 2, action: 'LOWER_BID', multiplier: 0.85, cooldown: 4, reason: 'escalation_L2_moderate' };
  }
  if (leads > 0 && cpl > maxCPL) {
    return { level: 1, action: 'LOWER_BID', multiplier: 0.92, cooldown: 2, reason: 'escalation_L1_soft' };
  }
  // No leads, below stop threshold
  if (leads === 0 && spend >= minSpendForDecision) {
    return { level: 2, action: 'LOWER_BID', multiplier: 0.85, cooldown: 2, reason: 'no_leads_lower' };
  }
  return { level: 0, action: 'HOLD', multiplier: 1.0, cooldown: 0, reason: 'default_hold' };
};

// --- WARMUP LOGIC ---
// New teasers start with MAX bid to get into auction fast
// Phase 0: brand new (0 spend) -> set max_bid for geo
// Phase 1: $0-100 spent -> hold at max_bid, collect CTR data
// Phase 2: $100-300 spent -> if CTR good + leads coming, hold. If bad CTR -> lower
// Phase 3: $300+ -> full optimization mode
const getWarmupAction = (spend, clicks, shows, leads, ctr, currentBid, maxBid, minBid) => {
  if (spend < 10) {
    // Phase 0: Set to max bid for geo to get into auction
    if (currentBid < maxBid * 0.9) {
      return { action: 'RAISE_BID', newBid: maxBid, reason: 'warmup_phase0_max_bid', phase: 0 };
    }
    return { action: 'HOLD', newBid: currentBid, reason: 'warmup_phase0_already_max', phase: 0 };
  }
  if (spend < 100) {
    // Phase 1: Collect data at max bid
    if (clicks < 10 && shows > 3000) {
      // Dead creative, terrible CTR even at max bid
      return { action: 'STOP', newBid: currentBid, reason: 'warmup_dead_creative', phase: 1 };
    }
    return { action: 'HOLD', newBid: currentBid, reason: 'warmup_phase1_collecting', phase: 1 };
  }
  if (spend < 300) {
    // Phase 2: Evaluate
    if (leads > 0) {
      return null; // Good, switch to full optimization
    }
    if (ctr < 0.1 && shows > 5000) {
      return { action: 'STOP', newBid: currentBid, reason: 'warmup_low_ctr', phase: 2 };
    }
    return { action: 'HOLD', newBid: currentBid, reason: 'warmup_phase2_evaluating', phase: 2 };
  }
  // Phase 3+: full optimization
  return null;
};

// --- MAIN LOOP ---
const actions = [];

statsData.forEach(d => {
  const adId = d.ad_id;
  const spend = Number(d.money) || 0;
  const clicks = Number(d.clicks_count) || 0;
  const shows = Number(d.shows_count) || 0;
  const ctr = shows > 0 ? (clicks / shows * 100) : 0;
  const adInfo = adsMap[adId] || { current_bid: 0, geos: [] };
  const currentBid = adInfo.current_bid;

  if (currentBid === 0) return; // Skip ads without bid data

  // Geo payout
  const primaryGeo = adInfo.geos.length > 0 ? adInfo.geos[0] : null;
  const geoPayout = primaryGeo && geoMap[primaryGeo] ? geoMap[primaryGeo] : DEFAULT_PAYOUT;
  const maxCPL = geoPayout.max_cpl;
  const maxCeiling = geoPayout.max_bid;
  const minFloor = geoPayout.min_bid;

  // CRM
  const crm = crmMap[adId] || { leads: 0, deps: 0, rev: 0 };
  const totalLeads = crm.leads;
  const depositors = crm.deps;
  const cpl = totalLeads > 0 ? (spend / totalLeads) : (spend > 0 ? Infinity : 0);
  const depRate = totalLeads > 0 ? (depositors / totalLeads * 100) : 0;

  // Position
  const pos = posMap[adId] || { avg: 99, best: 99 };
  const avgPos = pos.avg;
  const isTopPos = avgPos <= 2;
  const isGoodPos = avgPos <= 5;

  // Teaser state
  const teaserState = stateMap[adId] || {};
  const escalationFailures = Number(teaserState.escalation_failures) || 0;

  // --- RATE LIMITING ---
  const recentChanges = bidHistoryMap[adId] || [];
  const lastChange = recentChanges[0];
  const hoursSinceLastChange = lastChange
    ? (Date.now() - new Date(lastChange.changed_at).getTime()) / (1000 * 60 * 60)
    : 999;

  // Count today's changes
  const today = new Date().toISOString().slice(0, 10);
  const todayChanges = recentChanges.filter(c => c.changed_at && c.changed_at.toString().slice(0, 10) === today);
  const changesCount = todayChanges.length;

  // Cumulative bid change today
  let cumulativeChange = 1.0;
  todayChanges.forEach(c => {
    if (c.old_bid > 0) cumulativeChange *= (Number(c.new_bid) / Number(c.old_bid));
  });

  let action = 'HOLD';
  let newBid = currentBid;
  let reason = '';
  let escalationLevel = 0;
  let warmupPhase = -1;  // -1 = not in warmup
  let createRollback = false;

  // --- WARMUP CHECK (new teasers) ---
  const warmupResult = getWarmupAction(spend, clicks, shows, totalLeads, ctr, currentBid, maxCeiling, minFloor);
  if (warmupResult) {
    action = warmupResult.action;
    newBid = warmupResult.newBid;
    reason = `${primaryGeo||'?'} ${warmupResult.reason}: $${spend.toFixed(0)} spent, ${clicks}cl, ${totalLeads}L`;
    warmupPhase = warmupResult.phase;
  } else {
    // --- FULL OPTIMIZATION MODE ---

    // Check escalation first
    const escResult = getEscalationAction(
      teaserState.escalation_level || 0, cpl, maxCPL, spend, totalLeads, escalationFailures, isConservative
    );

    if (escResult && escResult.action !== 'HOLD' && escResult.action !== null) {
      // Rate limit check
      if (hoursSinceLastChange < escResult.cooldown) {
        action = 'HOLD';
        reason = `${primaryGeo||'?'} Cooldown: ${hoursSinceLastChange.toFixed(1)}h < ${escResult.cooldown}h min`;
      } else if (changesCount >= MAX_BID_CHANGES_PER_DAY && escResult.action !== 'STOP') {
        action = 'HOLD';
        reason = `${primaryGeo||'?'} Rate limit: ${changesCount}/${MAX_BID_CHANGES_PER_DAY} changes today`;
      } else if (cumulativeChange < MAX_CUMULATIVE_CHANGE_DOWN && escResult.multiplier < 1.0) {
        action = 'HOLD';
        reason = `${primaryGeo||'?'} Cumulative limit: already ${((1-cumulativeChange)*100).toFixed(0)}% down today`;
      } else {
        action = escResult.action;
        escalationLevel = escResult.level;
        if (action === 'LOWER_BID') {
          newBid = currentBid * escResult.multiplier;
          reason = `${primaryGeo||'?'} L${escResult.level} ${escResult.reason}: CPL $${cpl === Infinity ? 'inf' : cpl.toFixed(0)} max:$${maxCPL.toFixed(0)} ${totalLeads}L/${depositors}D -${((1-escResult.multiplier)*100).toFixed(0)}%`;
          createRollback = true;
        } else if (action === 'STOP') {
          reason = `${primaryGeo||'?'} L${escResult.level} ${escResult.reason}: $${spend.toFixed(0)} spent, ${totalLeads}L, ${clicks}cl`;
        }
      }
    } else {
      // Profitable logic (leads exist and CPL <= maxCPL)
      if (totalLeads > 0) {
        if (isConservative) {
          action = 'HOLD';
          reason = `${primaryGeo||'?'} Conservative mode: CPL $${cpl.toFixed(0)}, ${totalLeads}L/${depositors}D`;
        } else if (cpl <= maxCPL * 0.5 && totalLeads >= 3 && !isTopPos) {
          // Very profitable + not top position -> raise
          if (changesCount < MAX_BID_CHANGES_PER_DAY && hoursSinceLastChange >= MIN_COOLDOWN_HOURS) {
            action = 'RAISE_BID';
            const raiseMultiplier = 1.15 * timeMultiplier; // Time-adjusted
            newBid = currentBid * Math.min(raiseMultiplier, 1.30); // Cap at +30%
            reason = `${primaryGeo||'?'} Profitable CPL $${cpl.toFixed(0)} (max $${maxCPL.toFixed(0)}), ${totalLeads}L/${depositors}D, pos ${avgPos}, +${((Math.min(raiseMultiplier,1.30)-1)*100).toFixed(0)}% [${timePeriod}]`;
            createRollback = true;
          } else {
            action = 'HOLD';
            reason = `${primaryGeo||'?'} Profitable but rate limited (${changesCount} changes, ${hoursSinceLastChange.toFixed(1)}h ago)`;
          }
        } else if (cpl <= maxCPL * 0.5 && totalLeads >= 3 && isTopPos) {
          action = 'HOLD';
          reason = `${primaryGeo||'?'} Profitable CPL $${cpl.toFixed(0)} at top pos ${avgPos}`;
        } else if (cpl <= maxCPL * 0.75 && totalLeads >= 2 && !isGoodPos) {
          if (changesCount < MAX_BID_CHANGES_PER_DAY && hoursSinceLastChange >= MIN_COOLDOWN_HOURS) {
            action = 'RAISE_BID';
            const raiseMultiplier = 1.10 * timeMultiplier;
            newBid = currentBid * Math.min(raiseMultiplier, 1.20);
            reason = `${primaryGeo||'?'} Good CPL $${cpl.toFixed(0)} (max $${maxCPL.toFixed(0)}), ${totalLeads}L/${depositors}D, pos ${avgPos}, +${((Math.min(raiseMultiplier,1.20)-1)*100).toFixed(0)}% [${timePeriod}]`;
            createRollback = true;
          } else {
            action = 'HOLD';
            reason = `${primaryGeo||'?'} Good CPL but rate limited`;
          }
        } else if (cpl <= maxCPL) {
          action = 'HOLD';
          reason = `${primaryGeo||'?'} OK CPL $${cpl.toFixed(0)}, ${totalLeads}L/${depositors}D, pos ${avgPos}`;
        }
        // CPL > maxCPL handled by escalation above
      } else {
        // 0 leads handled by escalation above
        if (spend < minSpendForDecision) {
          action = 'HOLD';
          reason = `${primaryGeo||'?'} 0L, $${spend.toFixed(2)} spent (need $${minSpendForDecision}), waiting`;
        }
        // Dead creative check
        if (clicks < 10 && shows > 5000) {
          action = 'STOP';
          reason = `${primaryGeo||'?'} Dead creative: ${clicks}cl / ${shows}sh in 3d`;
        }
      }
    }
  }

  // --- APPLY CEILINGS/FLOORS ---
  if (action !== 'HOLD' && action !== 'STOP') {
    if (newBid > maxCeiling) newBid = maxCeiling;
    if (newBid < minFloor) newBid = minFloor;
    newBid = Math.round(newBid * 10000) / 10000;

    // Don't emit change if bid is effectively the same
    if (Math.abs(newBid - currentBid) < 0.0001) {
      action = 'HOLD';
      reason += ' (bid unchanged after ceiling/floor)';
    }
  }

  // --- OUTPUT ---
  if (action !== 'HOLD') {
    actions.push({
      json: {
        ad_id: adId,
        action: action,
        current_bid: currentBid,
        new_bid: action === 'STOP' ? currentBid : newBid,
        geo: primaryGeo || 'unknown',
        cpl: cpl === Infinity ? -1 : Math.round(cpl * 100) / 100,
        max_cpl: Math.round(maxCPL * 100) / 100,
        geo_payout: Math.round(geoPayout.avg_payout),
        geo_approval: geoPayout.avg_approval,
        leads: totalLeads,
        depositors: depositors,
        dep_rate: Math.round(depRate * 100) / 100,
        avg_position: avgPos,
        clicks: clicks,
        shows: shows,
        spend: Math.round(spend * 100) / 100,
        ctr: Math.round(ctr * 10000) / 10000,
        reason: reason,
        escalation_level: escalationLevel,
        warmup_phase: warmupPhase,
        time_period: timePeriod,
        time_multiplier: timeMultiplier,
        create_rollback: createRollback,
        changes_today: changesCount,
        cumulative_change: Math.round(cumulativeChange * 1000) / 1000
      }
    });
  }
});

if (actions.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No bid changes needed', time_period: timePeriod } }];
}

return actions;

// Verify API response and prepare logging data
const input = $input.first().json;
const originalAction = $('Stop or Bid Change?').first().json;

// Check if API returned error
const statusCode = input?.statusCode || input?.code || 200;
const isError = statusCode >= 400 || input?.error || input?.message?.includes('error');

return [{
  json: {
    ...originalAction,
    api_success: !isError,
    api_status: statusCode,
    api_response: isError ? JSON.stringify(input).slice(0, 200) : 'ok'
  }
}];

// Create rollback snapshot if needed
const item = $input.first().json;
if (!item.create_rollback) return [];

return [{ json: {
  ad_id: item.ad_id,
  snapshot_bid: item.current_bid,
  snapshot_cpl: item.cpl === -1 ? null : item.cpl,
  snapshot_ctr: item.ctr
} }];

const items = $input.all();
const changes = items.filter(i => i.json.action && i.json.action !== 'NONE' && i.json.action !== 'ABORT');

if (changes.length === 0) return [];

const stops = changes.filter(i => i.json.action === 'STOP');
const raises = changes.filter(i => i.json.action === 'RAISE_BID');
const lowers = changes.filter(i => i.json.action === 'LOWER_BID');
const warmups = changes.filter(i => i.json.warmup_phase >= 0);

const timePeriod = changes[0]?.json?.time_period || 'unknown';

let msg = `SMART BIDDER v2 ${$now.toFormat('dd.MM.yyyy HH:mm')} [${timePeriod}]\n`;
msg += `Total: ${changes.length} | Up: ${raises.length} | Down: ${lowers.length} | Stop: ${stops.length} | Warmup: ${warmups.length}\n\n`;

if (stops.length > 0) {
  msg += `STOPPED:\n`;
  stops.forEach(s => {
    const cplStr = s.json.cpl > 0 ? `CPL:$${s.json.cpl}` : 'no leads';
    msg += `  ${s.json.geo} #${s.json.ad_id}: L${s.json.escalation_level} ${s.json.leads||0}L/${s.json.depositors||0}D ${cplStr} $${s.json.spend}spent\n`;
  });
  msg += `\n`;
}

if (raises.length > 0) {
  msg += `BID UP:\n`;
  raises.slice(0, 10).forEach(r => {
    msg += `  ${r.json.geo} #${r.json.ad_id}: $${r.json.current_bid}->${r.json.new_bid} ${r.json.leads||0}L/${r.json.depositors||0}D CPL:$${r.json.cpl} [${r.json.changes_today}/3]\n`;
  });
  msg += `\n`;
}

if (lowers.length > 0) {
  msg += `BID DOWN:\n`;
  lowers.slice(0, 10).forEach(l => {
    const cplStr = l.json.cpl > 0 ? `CPL:$${l.json.cpl}` : 'no leads';
    msg += `  ${l.json.geo} #${l.json.ad_id}: L${l.json.escalation_level} $${l.json.current_bid}->${l.json.new_bid} ${l.json.leads||0}L/${l.json.depositors||0}D ${cplStr} [${l.json.changes_today}/3]\n`;
  });
  msg += `\n`;
}

if (warmups.length > 0) {
  msg += `WARMUP:\n`;
  warmups.slice(0, 5).forEach(w => {
    msg += `  ${w.json.geo} #${w.json.ad_id}: phase ${w.json.warmup_phase} $${w.json.current_bid}->${w.json.new_bid} ${w.json.reason}\n`;
  });
}

return [{ json: { message: msg } }];
